        parts=[("Piso",s_floor,ABS[floor]),("Cielo",s_floor,ABS[ceiling]),("Muros",s_walls,ABS[walls])]
        A=sum(s*a for _,s,a in parts); V=L*W*H; rt=.161*V/A
